// Promise
function fetchData(url) {
    return new Promise((resolve, reject) => {
        setTimeout(() => {
            if (url) resolve({ data: 'Success!' });
            else reject(new Error('No URL'));
        }, 1000);
    });
}

// Using .then()
fetchData('/api')
    .then(result => console.log(result))
    .catch(err => console.error(err));

// Using async/await
async function getData() {
    try {
        const result = await fetchData('/api');
        console.log(result);
    } catch (err) {
        console.error(err);
    }
}

getData();
